const registros = $input.all();
const hoy = new Date();

// Calculamos que mes y anio corresponden al mes anterior
// Si estamos en enero, el mes anterior es diciembre del anio pasado
const mesAnterior = hoy.getMonth() === 0 ? 11 : hoy.getMonth() - 1;
const anio = hoy.getMonth() === 0 ? hoy.getFullYear() - 1 : hoy.getFullYear();

const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio',
               'Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const nombreMes = meses[mesAnterior];

// Filtramos solo los registros que corresponden al mes anterior
const delMes = registros.filter(r => {
  const partes = r.json.fecha.split('/');
  const mes = parseInt(partes[1]) - 1; // Los meses en JS van de 0 a 11
  const anioR = parseInt(partes[2]);
  return mes === mesAnterior && anioR === anio;
});

// Agrupamos los registros por alumno para calcular estadisticas individuales
const porAlumno = {};
for (const r of delMes) {
  const nombre = r.json.alumno;
  if (!porAlumno[nombre]) {
    porAlumno[nombre] = { total: 0, presentes: 0, ausencias: 0, curso: r.json.curso };
  }
  porAlumno[nombre].total++;
  if (r.json.presente === 'true' || r.json.presente === true) {
    porAlumno[nombre].presentes++;
  } else {
    porAlumno[nombre].ausencias++;
  }
}

// Generamos el informe con formato de texto legible
let informe = `INFORME DE ASISTENCIA - ${nombreMes} ${anio}\n`;
informe += '='.repeat(50) + '\n\n';

let totalAlumnos = Object.keys(porAlumno).length;
let totalAusencias = 0;

for (const [nombre, datos] of Object.entries(porAlumno)) {
  const porcentaje = datos.total > 0 ? ((datos.presentes / datos.total) * 100).toFixed(1) : '0.0';
  informe += `${nombre} (${datos.curso})\n`;
  informe += `  Dias lectivos: ${datos.total} | Presencias: ${datos.presentes} | Ausencias: ${datos.ausencias}\n`;
  informe += `  Porcentaje de asistencia: ${porcentaje}%\n`;
  // Marcamos a los alumnos con mas de 3 ausencias como alerta
  if (datos.ausencias > 3) {
    informe += `  ALERTA: Mas de 3 ausencias en el mes\n`;
  }
  informe += '\n';
  totalAusencias += datos.ausencias;
}

// Resumen general al final del informe
informe += '\nRESUMEN GENERAL\n';
informe += '-'.repeat(30) + '\n';
informe += `Total alumnos: ${totalAlumnos}\n`;
informe += `Total ausencias del mes: ${totalAusencias}\n`;

// Lista de alumnos que necesitan seguimiento
const alumnosAlerta = Object.entries(porAlumno)
  .filter(([_, d]) => d.ausencias > 3)
  .map(([nombre, _]) => nombre);

if (alumnosAlerta.length > 0) {
  informe += `\nAlumnos con mas de 3 ausencias que requieren seguimiento: ${alumnosAlerta.join(', ')}\n`;
}

return [{ json: { informe, nombreMes, anio, totalAlumnos, totalAusencias, alumnosAlerta: alumnosAlerta.join(', ') } }];

